#include <bits/stdc++.h>
using namespace std;vector<int>g[1001];bool vis[1001];
void dfs(int u){vis[u]=1;for(int v:g[u])if(!vis[v])dfs(v);}
int main(){int n,m;cin>>n>>m;for(int i=0;i<m;i++){int a,b;cin>>a>>b;g[a].push_back(b);g[b].push_back(a);}int c=0;for(int i=1;i<=n;i++)if(!vis[i]){c++;dfs(i);}cout<<c<<"\n";}
